SELECT SUM("STORE_SALES"."SS_QUANTITY")
FROM "tpcds"."STORE_SALES",
"tpcds"."STORE",
"tpcds"."CUSTOMER_DEMOGRAPHICS",
"tpcds"."CUSTOMER_ADDRESS",
"tpcds"."DATE_DIM"
WHERE "STORE"."S_STORE_SK" = "STORE_SALES"."SS_STORE_SK" AND "STORE_SALES"."SS_SOLD_DATE_SK" = "DATE_DIM"."D_DATE_SK" AND "DATE_DIM"."D_YEAR" = 1998 AND ("CUSTOMER_DEMOGRAPHICS"."CD_DEMO_SK" = "STORE_SALES"."SS_CDEMO_SK" AND "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = '[MS.1]' AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = '[ES.1]' AND ("STORE_SALES"."SS_SALES_PRICE" >= 100.00 AND "STORE_SALES"."SS_SALES_PRICE" <= 150.00) OR "CUSTOMER_DEMOGRAPHICS"."CD_DEMO_SK" = "STORE_SALES"."SS_CDEMO_SK" AND "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = '[MS.1]' AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = '[ES.1]' AND ("STORE_SALES"."SS_SALES_PRICE" >= 50.00 AND "STORE_SALES"."SS_SALES_PRICE" <= 100.00) OR "CUSTOMER_DEMOGRAPHICS"."CD_DEMO_SK" = "STORE_SALES"."SS_CDEMO_SK" AND "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = '[MS.1]' AND "CUSTOMER_DEMOGRAPHICS"."CD_EDUCATION_STATUS" = '[ES.1]' AND ("STORE_SALES"."SS_SALES_PRICE" >= 150.00 AND "STORE_SALES"."SS_SALES_PRICE" <= 200.00)) AND ("STORE_SALES"."SS_ADDR_SK" = "CUSTOMER_ADDRESS"."CA_ADDRESS_SK" AND "CUSTOMER_ADDRESS"."CA_COUNTRY" = 'United States' AND CAST("CUSTOMER_ADDRESS"."CA_STATE" AS VARCHAR(9)) IN ('[STATE.1]', '[STATE.2]', '[STATE.3]') AND (CAST("STORE_SALES"."SS_NET_PROFIT" AS DECIMAL(12, 2)) >= 0.00 AND CAST("STORE_SALES"."SS_NET_PROFIT" AS DECIMAL(12, 2)) <= 2000.00) OR "STORE_SALES"."SS_ADDR_SK" = "CUSTOMER_ADDRESS"."CA_ADDRESS_SK" AND "CUSTOMER_ADDRESS"."CA_COUNTRY" = 'United States' AND CAST("CUSTOMER_ADDRESS"."CA_STATE" AS VARCHAR(9)) IN ('[STATE.4]', '[STATE.5]', '[STATE.6]') AND (CAST("STORE_SALES"."SS_NET_PROFIT" AS DECIMAL(12, 2)) >= 150.00 AND CAST("STORE_SALES"."SS_NET_PROFIT" AS DECIMAL(12, 2)) <= 3000.00) OR "STORE_SALES"."SS_ADDR_SK" = "CUSTOMER_ADDRESS"."CA_ADDRESS_SK" AND "CUSTOMER_ADDRESS"."CA_COUNTRY" = 'United States' AND CAST("CUSTOMER_ADDRESS"."CA_STATE" AS VARCHAR(9)) IN ('[STATE.7]', '[STATE.8]', '[STATE.9]') AND (CAST("STORE_SALES"."SS_NET_PROFIT" AS DECIMAL(12, 2)) >= 50.00 AND CAST("STORE_SALES"."SS_NET_PROFIT" AS DECIMAL(12, 2)) <= 25000.00))
